-- Wire the entity's default control accounts (unblocks AR/AP/COGS posting + drop-ship docs).
DO $$ DECLARE v_rof uuid; BEGIN
  SELECT id INTO v_rof FROM entities WHERE code='ROF';
  UPDATE entities SET
    default_ar_account_id      = (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='1200'),
    default_ap_account_id      = (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='2000'),
    default_revenue_account_id = (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='4000'),
    default_cogs_account_id    = (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='5000'),
    default_inventory_account_id        = COALESCE(default_inventory_account_id,        (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='1300')),
    default_bank_account_id             = COALESCE(default_bank_account_id,             (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='1000')),
    default_retained_earnings_account_id= (SELECT id FROM gl_accounts WHERE entity_id=v_rof AND code='3900')
  WHERE id=v_rof;
END $$;
